const requiredFields = ['item_id', 'source_type', 'source_name', 'title', 'content_text'];
const missingFields = requiredFields.filter((field) => !String($json[field] || '').trim());
if (missingFields.length) {
  throw new Error(`Normalized item missing required fields: ${missingFields.join(', ')}`);
}

const embeddingBaseUrl = String($env.EMBEDDING_BASE_URL || '').trim().replace(/\/*$/, '');
const embeddingModel = String($env.EMBEDDING_MODEL || '').trim();
const embeddingApiKey = String($env.EMBEDDING_API_KEY || '').trim();
const embeddingInputMaxChars = Number($env.EMBEDDING_INPUT_MAX_CHARS || 8000);
const qdrantCollection = String($env.QDRANT_COLLECTION || 'article_embeddings').trim() || 'article_embeddings';
const qdrantVectorSize = Number($env.QDRANT_VECTOR_SIZE || 0);
const diffThreshold = Number($env.QDRANT_DIFF_THRESHOLD || 0.85);
const silentThreshold = Number($env.QDRANT_SILENT_THRESHOLD || 0.97);
const searchText = String($json.search_text || [
  String($json.title || '').trim(),
  String($json.upstream_summary || '').trim(),
  String($json.content_text || '').trim()
].filter(Boolean).join('\n\n')).trim().slice(0, embeddingInputMaxChars);

if (!embeddingBaseUrl) {
  throw new Error('EMBEDDING_BASE_URL is required for 03_qdrant_gate');
}
if (!embeddingModel) {
  throw new Error('EMBEDDING_MODEL is required for 03_qdrant_gate');
}
if (!embeddingApiKey) {
  throw new Error('EMBEDDING_API_KEY is required for 03_qdrant_gate');
}
if (!Number.isInteger(embeddingInputMaxChars) || embeddingInputMaxChars < 200) {
  throw new Error('EMBEDDING_INPUT_MAX_CHARS must be an integer >= 200');
}
if (!Number.isInteger(qdrantVectorSize) || qdrantVectorSize <= 0) {
  throw new Error('QDRANT_VECTOR_SIZE must be a positive integer');
}
if (!Number.isFinite(diffThreshold) || !Number.isFinite(silentThreshold)) {
  throw new Error('QDRANT_DIFF_THRESHOLD and QDRANT_SILENT_THRESHOLD must be numeric');
}
if (!(diffThreshold > 0 && diffThreshold < silentThreshold && silentThreshold <= 1)) {
  throw new Error('Expected 0 < QDRANT_DIFF_THRESHOLD < QDRANT_SILENT_THRESHOLD <= 1');
}
if (searchText.length < 80) {
  throw new Error('search_text is too short for reliable dedupe; expected at least 80 characters after prefilter');
}

return {
  json: {
    ...$json,
    embedding_base_url: embeddingBaseUrl,
    embedding_model: embeddingModel,
    embedding_input_max_chars: embeddingInputMaxChars,
    qdrant_base_url: 'http://qdrant:6333',
    qdrant_collection: qdrantCollection,
    qdrant_vector_size: qdrantVectorSize,
    qdrant_diff_threshold: diffThreshold,
    qdrant_silent_threshold: silentThreshold,
    embedding_input: searchText,
    search_text: searchText
  }
};

return {
  json: {
    ...$json,
    embedding_endpoint: `${$json.embedding_base_url}/embeddings`,
    embedding_request: {
      model: $json.embedding_model,
      input: $json.embedding_input,
      encoding_format: 'float'
    }
  }
};

const original = $('Build Embedding Request').item.json || {};
const embedding = $json?.data?.[0]?.embedding;
if (!Array.isArray(embedding)) {
  throw new Error('Embedding response did not include data[0].embedding');
}
if (embedding.length !== Number(original.qdrant_vector_size)) {
  throw new Error(`Embedding vector length ${embedding.length} does not match QDRANT_VECTOR_SIZE ${original.qdrant_vector_size}`);
}

return {
  json: {
    ...original,
    embedding,
    qdrant_search_endpoint: `${original.qdrant_base_url}/collections/${encodeURIComponent(original.qdrant_collection)}/points/search`,
    qdrant_search_payload: {
      vector: embedding,
      limit: 1,
      with_payload: true
    }
  }
};

const original = $('Build Qdrant Search Request').item.json || {};
const matches = Array.isArray($json?.result)
  ? $json.result
  : Array.isArray($json)
    ? $json
    : [];
const match = matches[0] || null;
const matchedPayload = match?.payload || null;
const matchedScore = Number(match?.score || 0);
const sameItem = Boolean(matchedPayload && matchedPayload.item_id === original.item_id);
const sameContent = Boolean(sameItem && matchedPayload.content_hash === original.content_hash);

let dedupeAction = 'full_push';
if (sameContent) {
  dedupeAction = 'silent';
} else if (sameItem) {
  dedupeAction = 'diff_push';
} else if (match && matchedScore >= Number(original.qdrant_silent_threshold)) {
  dedupeAction = 'silent';
} else if (match && matchedScore >= Number(original.qdrant_diff_threshold)) {
  dedupeAction = 'diff_push';
}

const shouldContinueToLlm = dedupeAction !== 'silent';
const notificationMode = dedupeAction === 'silent'
  ? 'silent'
  : dedupeAction === 'diff_push'
    ? 'incremental'
    : 'full';

return {
  json: {
    ...original,
    dedupe_action: dedupeAction,
    notification_mode: notificationMode,
    should_continue_to_llm: shouldContinueToLlm,
    should_write_to_vault: shouldContinueToLlm,
    should_notify: shouldContinueToLlm,
    should_upsert_qdrant: shouldContinueToLlm,
    matched_payload: matchedPayload,
    matched_score: matchedScore,
    matched_same_item: sameItem,
    matched_same_content: sameContent,
    status: dedupeAction === 'silent' ? 'deduped' : (String(original.status || 'raw').trim() || 'raw'),
    qdrant_operation: shouldContinueToLlm ? 'pending' : 'skipped',
    qdrant_upsert_response: null
  }
};

return {
  json: {
    ...$json,
    matched_score: Number(Number($json.matched_score || 0).toFixed(4)),
    qdrant_operation: String($json.qdrant_operation || 'skipped').trim() || 'skipped',
    qdrant_upsert_response: $json.qdrant_upsert_response ?? null
  }
};
